Here's a minimal API endpoint handling multipart form uploads with multiple images and a description:

```csharp
using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Increase the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(options =>
{
    options.Limits.MaxRequestBodySize = 50 * 1024 * 1024;
});

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Ensure it's a multipart form request
    if (!request.HasFormContentType)
        return Results.BadRequest("Expected a multipart/form-data request.");

    var form = await request.ReadFormAsync(new FormOptions
    {
        MultipartBodyLengthLimit = 50 * 1024 * 1024
    });

    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images");

    if (files.Count == 0)
        return Results.BadRequest("No image files provided.");

    var savedFiles = new List<string>();

    foreach (var file in files)
    {
        // Validate content type
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"File '{file.FileName}' is not an image.");

        var savePath = Path.Combine("uploads", $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}");
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(savePath);
        await file.CopyToAsync(stream);

        savedFiles.Add(savePath);
    }

    return Results.Ok(new
    {
        Description = description,
        FileCount = savedFiles.Count,
        Paths = savedFiles
    });
})
.DisableAntiforgery();

app.Run();
```

**Key points:**

- **Kestrel limit** — `MaxRequestBodySize` must be raised (default is ~30 MB).
- **`FormOptions.MultipartBodyLengthLimit`** — controls the per-part/total multipart size.
- **`form.Files.GetFiles("images")`** — retrieves all files submitted under the `images` field name.
- **`.DisableAntiforgery()`** — needed in .NET 8+ since antiforgery is on by default for form endpoints.

A matching `curl` test:

```bash
curl -X POST http://localhost:5000/upload \
  -F "description=My vacation photos" \
  -F "images=@photo1.jpg" \
  -F "images=@photo2.png"
```
